// BusTrendChart.js
import React from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";

const BusTrendChart = ({ buses }) => {
  const activeCount = buses.filter(b => b.status === "normal").length;
  const ghostCount = buses.filter(b => b.status === "ghost").length;
  const anomalyCount = buses.filter(b => b.status === "anomaly").length;

  const trendData = [
    { time: new Date().toLocaleTimeString(), normal: activeCount, ghost: ghostCount, anomaly: anomalyCount }
  ];

  return (
    <div style={{
      width: "90%",
      margin: "20px auto",
      backgroundColor: "white",
      padding: "10px",
      borderRadius: "8px"
    }}>
      <LineChart width={800} height={250} data={trendData}>
        <XAxis dataKey="time" />
        <YAxis />
        <Tooltip />
        <CartesianGrid stroke="#f5f5f5" />
        <Line type="monotone" dataKey="normal" stroke="green" />
        <Line type="monotone" dataKey="ghost" stroke="red" />
        <Line type="monotone" dataKey="anomaly" stroke="orange" />
      </LineChart>
    </div>
  );
};

export default BusTrendChart;
